class Solution {
public:
    void solve(vector<int>& front, vector<int>& rear, int &res, int q1, int q2) {
        if (q1 == 1) {
            front.push_back(q2);
            return;
        }
        if (q1 == 2) {
            rear.push_back(q2);
            return;
        }
        if (q1 == 3) {
            if (!front.empty()) res = front[0]; else res = -1;
            front.erase(front.begin());
            return;
        }
        if (q1 == 4) {
            if (!rear.empty()) res = rear[rear.size()-1]; else res = -1;
            rear.pop_back();
            return;
        }
    }
    void printQueue(vector<int> &front, vector<int> &rear) {
        if (front.empty()) cout << -1 << endl;
        else cout << front[0] << endl;
    }
};

