class Solution {
public:
    void solve(int front[], int rear[], int &res, int q1, int q2) {
        if (q1 == 1) {
            for (int i = 0; i < front.length; i++) {
                if (front[i] == q2) rear.push_back(front[i]);
            }
            return;
        }
        if (q1 == 2) {
            for (int i = 0; i < rear.length; i++) {
                if (rear[i] == q2) front.push(rear[i]);
            }
            return;
        }
        if (q1 == 3) {
            if (front.length != 0) res = front[0]; else res = -1;
            front = front.subList(1, front.length);
            return;
        }
        if (q1 == 4) {
            if (rear.length != 0) res = rear[rear.length - 1]; else res = -1;
            rear = rear.subList(0, rear.length - 1);
            return;
        }
    }
    void printQueue(int front[], int rear[]) {
        if (front.length == 0) System.out.println("-1");
        else System.out.println(front[0]);
    }
};

