    def solve(self, front, rear, res, q1, q2):
        if q1 == 1:
            front.append(q2)
            return
        if q1 == 2:
            rear.append(q2)
            return
        if q1 == 3:
            if front:
                res = front[0]
            else:
                res = -1
            front.pop(0)
            return
        if q1 == 4:
            if rear:
                res = rear[-1]
            else:
                res = -1
            rear.pop()
            return
